using ModelContextProtocol.Server;
using System.ComponentModel;

namespace McpHttpServer.Tools;

[McpServerToolType]
public static class EchoTool
{
    [McpServerTool, Description("Echoes the input message back to the caller.")]
    public static string Echo([Description("The message to echo")] string message)
        => $"Echo: {message}";
}

using ModelContextProtocol.Protocol.Types;
using ModelContextProtocol.Server;

namespace McpHttpServer.Resources;

public static class ConfigResource
{
    /// <summary>
    /// Registers a static resource that returns application configuration data.
    /// </summary>
    public static void Register(IMcpServerBuilder builder)
    {
        builder.WithListResourcesHandler(async (ctx, ct) =>
        {
            return new ListResourcesResult
            {
                Resources =
                [
                    new Resource
                    {
                        Uri = "config://app/settings",
                        Name = "Application Settings",
                        Description = "Returns the current application configuration",
                        MimeType = "application/json",
                    }
                ]
            };
        });

        builder.WithReadResourceHandler(async (ctx, ct) =>
        {
            if (ctx.Params?.Uri != "config://app/settings")
            {
                throw new McpServerException("Resource not found");
            }

            var json = """
                {
                    "environment": "production",
                    "version": "1.0.0",
                    "features": {
                        "darkMode": true,
                        "betaAccess": false
                    },
                    "limits": {
                        "maxRequestsPerMinute": 100,
                        "maxUploadSizeMb": 50
                    }
                }
                """;

            return new ReadResourceResult
            {
                Contents =
                [
                    new ResourceContents
                    {
                        Uri = ctx.Params.Uri,
                        MimeType = "application/json",
                        Text = json,
                    }
                ]
            };
        });
    }
}

